ce": ["scenario=qa_gold_answer", "question_present=True", "actual_answer_present=True", "reference_answer_present=True"], "status": "needs_review"}], "taxonomy_error_types": ["needs_human_review"]}, "wrong_missing_extra": {}}, "project_extensions": {"display_contract": {"formatting": ["json formatting", "truncation", "output/reference alignment"], "output_source": "trace.live_result.extracted_output", "reference_source": "input"}, "error_taxonomy": ["answer_incorrect", "answer_incomplete", "question_misunderstood", "irrelevant_answer", "unsupported_claim", "hallucination", "context_not_used", "insufficient_context", "context_noise", "over_refusal", "format_error", "too_vague", "contradiction", "needs_human_review", "none"], "frontend_standard": {"batch_persistence": {"case_shape": "id, selected, input, output, reference, metadata, scenario, source, status, error", "transient_results": "do not persist full trace, judge, attribute, or frontend_view as durable case-pool source data"}, "frontend_view": {"live": "render Input, Output, Reference, Judge, Attribute, and scenario fields from protocol objects", "summary": "render same QA case-pool shape with compact per-case judge and attribute summaries"}}, "scenarios": ["qa_gold_answer", "qa_context_faithfulness", "qa_weak_quality"], "score_dimensions": ["correctness", "completeness", "key_point_coverage", "faithfulness", "relevance", "usefulness", "coherence", "risk_control", "clarity"], "verifiable_tools": {"available": false, "reason": "adapter has no get_verifiable_tools"}}, "project_info": {"description": "评估已产出的问答输入、输出、参考答案或上下文证据，支持样本级 scenario。", "name": "QA 评估项目", "project_id": "QA"}, "reference_panel": {"actual": {"actual_answer": "轻症赔付次数和金额取决于具体保险合同。一般情况下，轻症可以赔付多次，每次赔付金额通常为基本保险金额的20%至30%，且可能有次数上限（如3次或5次）和间隔期要求。建议查阅您的保险合同条款获取准确信息。"}, "reference": {"actual_answer": "通常情况下，您购买的重疾险合同中关于轻症责任的赔付规则如下：\n1. 轻症可以多次赔付，具体次数以合同约定为准（常见为3-5次）。每次确诊的轻症需满足合同定义的疾病标准，且两次轻症确诊之间通常有间隔期（如90天或180天）。\n2. 每次轻症赔付的金额一般为基本保额的一定比例，常见比例为20%-30%。例如保额50万，每次轻症可赔付10万-15万。部分产品轻症赔付后重疾保额不变，部分产品会相应减少。\n3. 需要注意，轻症责任可能设有分组限制，即同一组别的轻症只能赔付一次；另外，轻症赔付后合同继续有效，但累计赔付上限可能有限制。\n以上为一般规则，具体赔付条件、次数、金额比例请以您持有的保险合同条款为准。建议您查阅合同中的“保险责任”及“轻症疾病保险金”章节，或直接咨询保险公司客服获取准确信息。"}, "source": "input"}, "run_trace_summary": {"case_id": "mock-agent-QA-87e78ff7", "created_at": "2026-07-05T06:23:20.085051+00:00", "evidence_refs": [{"reference": {"actual_answer": "通常情况下，您购买的重疾险合同中关于轻症责任的赔付规则如下：\n1. 轻症可以多次赔付，具体次数以合同约定为准（常见为3-5次）。每次确诊的轻症需满足合同定义的疾病标准，且两次轻症确诊之间通常有间隔期（如90天或180天）。\n2. 每次轻症赔付的金额一般为基本保额的一定比例，常见比例为20%-30%。例如保额50万，每次轻症可赔付10万-15万。部分产品轻症赔付后重疾保额不变，部分产品会相应减少。\n3. 需要注意，轻症责任可能设有分组限制，即同一组别的轻症只能赔付一次；另外，轻症赔付后合同继续有效，但累计赔付上限可能有限制。\n以上为一般规则，具体赔付条件、次数、金额比例请以您持有的保险合同条款为准。建议您查阅合同中的“保险责任”及“轻症疾病保险金”章节，或直接咨询保险公司客服获取准确信息。"}, "scenario": "qa_gold_answer", "state_id": "collect_evidence", "type": "qa_sample_boundary"}], "execution_mode": "provided", "execution_trace": [{"error": "", "evidence": {"scenario": "qa_gold_answer"}, "stage": "qa.sample.normalize", "status": "succeeded", "timestamp": ""}, {"error": "", "evidence": "evaluated output read from uploaded sample", "stage": "qa.output.read", "status": "succeeded", "timestamp": ""}, {"error": "", "evidence": {"actual_answer_present": true}, "stage": "adapter.extract_output", "status": "succeeded", "timestamp": ""}], "extracted_output": {"actual_answer": "轻症赔付次数和金额取决于具体保险合同。一般情况下，轻症可以赔付多次，每次赔付金额通常为基本保险金额的20%至30%，且可能有次数上限（如3次或5次）和间隔期要求。建议查阅您的保险合同条款获取准确信息。"}, "gate_decisions": [{"checked_inputs": {"status": "ok", "trace": true}, "gate_id": "trace_available", "gate_type": "required_evidence", "passed": true, "reason": "trace exists", "recommended_transition": "", "recoverable": false}, {"checked_inputs": {"has_judge": true}, "gate_id": "consumer_contract_present", "gate_type": "consumer_contract_present", "passed": true, "reason": "consumer contract available", "recommended_transition": "build_business_expectations", "recoverable": true}, {"checked_inputs": {"expectation_count": 1}, "gate_id": "business_expectation_